form:Form.form:Scripts:
		var vuelta;
function LoadForm()
{   
	if(Ctrl('main').GetMode()=='NEW')
	{        
		if(vuelta !=1 )
		{        
			Ctrl('f_fechahora_sal_en').SetXValue('');
			Ctrl('f_fechahora_en_ent').SetXValue('');
			Ctrl('f_fechahora_sal_es').SetXValue('');
			Ctrl('f_fechahora_ent').SetXValue('');  
		}
	}
	EnableControls();
}
function EnableControls()
{
	if(Ctrl('oi_visitante').GetXValue()!='')
	{
		CtrlEnabled('oi_foto', true);
	} else
	{
		CtrlEnabled('oi_foto', false);
	}
}

