	if(Ctrl('oi_visitante').GetXValue()!='')
	{
		Ctrl('main').DoEvent('LoadQuery');
		EnableControls();
	}
}  */

function select_visitante()
{     
	vuelta = 1;
	if(Ctrl('oi_visitante').GetXValue()!='')
	{
		Ctrl('main').DoEvent('LoadQuery');
		EnableControls();
	}
}           

function valido() 
{    
	if(Ctrl('main').GetMode()=='NEW')
	{   

		var salida_estrevista=Ctrl('f_fechahora_sal_en').GetXValue().substr(0,12);
		var entrada_entrevista=Ctrl('f_fechahora_en_ent').GetXValue().substr(0,12);
		var salida_real=Ctrl('f_fechahora_sal').GetXValue().substr(0,12);
		var salida_estipulada=Ctrl('f_fechahora_sal_es').GetXValue().substr(0,12);
		var entrada_real=Ctrl('f_fechahora_ent').GetXValue().substr(0,12);  
		//var entrada_estimada=Ctrl('f_fechahora_ent_es').GetXValue();  

		if(salida_estipulada!='' && (salida_estipulada < entrada_real || salida_estipulada == entrada_real))
		{
			alert("La Fecha-Hora Salida Estipulada debe ser mayor a Fecha-Hora Entrada Real ");
			return false;
		}
		if(entrada_entrevista!='' && (entrada_entrevista < entrada_real || entrada_entrevista == entrada_real))
		{
			alert("La Fecha-Hora Entrada Entrevista debe ser mayor a Fecha-Hora Entrada Real ");
			return false;
		} 
		if(salida_estrevista!='' && (salida_estrevista < entrada_entrevista || salida_estrevista == entrada_entrevista))
		{
			alert("La Fecha-Hora Salida Entrevista debe ser mayor a Fecha-Hora Entrada Entrevista ");
			return false;
		}
		if(salida_estrevista!='' && (salida_estrevista < entrada_real || salida_estrevista == entrada_real))
		{
			alert("La Fecha-Hora Salida Entrevista debe ser mayor a Fecha-Hora Entrada Real ");
			return false;
		} 
		if(salida_estrevista!='' && salida_real!='' && (salida_estrevista > salida_real || salida_estrevista == salida_real))
		{
			alert("La Fecha-Hora Salida Entrevista debe ser mayor o igual a Fecha-Hora Salida Real ");
			return false;
		}    
		//Ctrl('main').DoEvent('BACK'); 
	}

	if(Ctrl('main').GetMode()=='EDIT')
	{
	  var salida_estrevista=Ctrl('f_fechahora_sal_en').GetXValue().substr(0,12);
		var entrada_entrevista=Ctrl('f_fechahora_en_ent').GetXValue().substr(0,12);
		var salida_estipulada=Ctrl('f_fechahora_sal_es').GetXValue().substr(0,12);
		var entrada_real=Ctrl('f_fechahora_ent').GetXValue().substr(0,12);  
		//var entrada_estimada=Ctrl('f_fechahora_ent_es').GetXValue();  

		if(salida_estipulada!='' && (salida_estipulada < entrada_real || salida_estipulada == entrada_real))
		{
			alert("La Fecha-Hora Salida Estipulada debe ser mayor a Fecha-Hora Entrada Real ");
			return false;
		}
		if(entrada_entrevista!='' && (entrada_entrevista < entrada_real || entrada_entrevista == entrada_real))
		{
			alert("La Fecha-Hora Entrada Entrevista debe ser mayor a Fecha-Hora Entrada Real ");
			return false;
		}   
		if(salida_estrevista!='' && (salida_estrevista < entrada_entrevista || salida_estrevista == entrada_entrevista))
		{
			alert("La Fecha-Hora Salida Entrevista debe ser mayor a Fecha-Hora Entrada Entrevista ");
			return false;
		}
		if(salida_estrevista!='' && (salida_estrevista < entrada_real || salida_estrevista == entrada_real))
		{
			alert("La Fecha-Hora Salida Entrevista debe ser mayor a Fecha-Hora Entrada Real ");
			return false;
		} 

		//Ctrl('main').DoEvent('BACK');
	}     
	Ctrl('main').DoEvent('BACK');
}   

function valido_accept() 
